 35	void nr_group_sequence_hopping(pucch_GroupHopping_t PUCCH_GroupHopping,
 36	                               uint32_t n_id,
 37	                               int n_hop,
 38	                               int nr_slot_tx,
 39	                               uint8_t *u,
 40	                               uint8_t *v)
 41	{
 42	  /*
 43	   * Implements TS 38.211 subclause 6.3.2.2.1 Group and sequence hopping
 44	   * The following variables are set by higher layers:
 45	   *    - PUCCH_GroupHopping:
 46	   *    - n_id: higher-layer parameter hoppingId
 47	   *    - n_hop: frequency hopping index
 48	   *             if intra-slot frequency hopping is disabled by the higher-layer parameter PUCCH-frequency-hopping
 49	   *                n_hop=0
 50	   *             if frequency hopping is enabled by the higher-layer parameter PUCCH-frequency-hopping
 51	   *                n_hop=0 for the first hop
 52	   *                n_hop=1 for the second hop
 53	   */
 54	  // depending on the value of the PUCCH_GroupHopping, we will obtain different values for u,v
 55	  //pucch_GroupHopping_t PUCCH_GroupHopping = ue->pucch_config_common_nr->pucch_GroupHopping; // from higher layers FIXME!!!
 56	  // n_id defined as per TS 38.211 subclause 6.3.2.2.1 (is given by the higher-layer parameter hoppingId)
 57	  // it is hoppingId from PUCCH-ConfigCommon:
 58	  // Cell-Specific scrambling ID for group hoppping and sequence hopping if enabled
 59	  // Corresponds to L1 parameter 'HoppingID' (see 38.211, section 6.3.2.2) BIT STRING (SIZE (10))
 60	  //uint16_t n_id = ue->pucch_config_common_nr->hoppingId; // from higher layers FIXME!!!
 61	#ifdef DEBUG_NR_PUCCH_TX
 62	  printf("\t\t [nr_group_sequence_hopping] PUCCH_GroupHopping=%u, n_id=%u \n",PUCCH_GroupHopping,n_id);
 63	#endif
 64	  uint8_t f_ss=0,f_gh=0;
 65	  *u=0;
 66	  *v = 0;
 67	#ifdef DEBUG_NR_PUCCH_TX
 68	  printf("\t\t [nr_group_sequence_hopping] calculating u,v -> ");
 69	#endif
 70	
 71	  if (PUCCH_GroupHopping == neither) { // PUCCH_GroupHopping 'neither'
 72	    f_ss = n_id%30;
 73	  }
 74	
 75	  if (PUCCH_GroupHopping == enable) { // PUCCH_GroupHopping 'enabled'
 76	    uint32_t c_init = floor(n_id / 30); // we initialize c_init to calculate u,v according to 6.3.2.2.1 of 38.211
 77	    int l = 32, minShift = (2 * nr_slot_tx + n_hop) << 3;
 78	    uint32_t *seq = gold_cache(c_init, (minShift + 31) / 32 + 8); // TS 38.211 Subclause 5.2.1
 79	    int goldIdx = 0;
 80	    for (int m=0; m<8; m++) {
 81	      while(minShift >= l) {
 82	        goldIdx++;
 83	        l = l+32;
 84	      }
 85	      AssertFatal(goldIdx < 8 + (minShift + 31) / 32, "");
 86	      int tmpShift = (minShift & ((1 << 5) - 1)); // minShift%32;
 87	      f_gh = f_gh + ((1 << m) * ((uint8_t)((seq[goldIdx] >> tmpShift) & 1)));
 88	      minShift ++;
 89	    }
 90	
 91	    f_gh = f_gh%30;
 92	    f_ss = n_id % 30;
 93	  }
 94	
 95	  if (PUCCH_GroupHopping == disable) { // PUCCH_GroupHopping 'disabled'
 96	    uint32_t c_init = (1 << 5) * floor(n_id / 30) + (n_id % 30); // we initialize c_init to calculate u,v
 97	    int goldIdx = 0;
 98	    f_ss = n_id%30;
 99	    int l = 32, minShift = (2 * nr_slot_tx + n_hop);
100	
101	    while(minShift >= l) {
102	      goldIdx++;
103	      l = l+32;
104	    }
105	    // TS 38.211 Subclause 5.2.1
106	    uint32_t *seq = gold_cache(c_init, goldIdx + 1);
107	    int tmpShift = (minShift & ((1 << 5) - 1)); // minShift%32;
108	    *v = (uint8_t)((seq[goldIdx] >> tmpShift) & 1);
109	    //    *v = (uint8_t)((s>>(2*nr_slot_tx+n_hop))&1); // Not sure we have to use nr_slot_tx FIXME!!!
110	  }
111	
112	  *u = (f_gh+f_ss)%30;
113	#ifdef DEBUG_NR_PUCCH_TX
114	  printf("%d,%d\n",*u,*v);
115	#endif
116	}
